import React, { useState, useEffect, useMemo } from 'react';
import { Product, Category, CartItem, WCSettings, Order, OrderSummary, Customer, OrderStatus, HeldOrder, ProductVariation } from './types';
import { fetchProducts, fetchCategories, fetchCustomers, createOrder } from './services/wooService';
import { getSecretValue } from './services/secretManagerService';
import ProductCard from './components/ProductCard';
import Cart from './components/Cart';
import CategoryFilter, { FAVORITES_ID } from './components/CategoryFilter';
import SettingsModal from './components/SettingsModal';
import AIAssistant from './components/AIAssistant';
import CheckoutModal from './components/CheckoutModal';
import OrderHistory from './components/OrderHistory';
import CustomerSelectionModal from './components/CustomerSelectionModal';
import HeldOrdersModal from './components/HeldOrdersModal';
import ProductDetailModal from './components/ProductDetailModal';
import ImageLightbox from './components/ImageLightbox';

const App: React.FC = () => {
  // --- State ---
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<number | null>(null);
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
  const [orderDiscount, setOrderDiscount] = useState<number>(0); // Lifted from Cart
  const [searchTerm, setSearchTerm] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [initMsg, setInitMsg] = useState<string | null>(null);

  // Checkout & History State
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [checkoutSummary, setCheckoutSummary] = useState<OrderSummary | null>(null);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isCustomerModalOpen, setIsCustomerModalOpen] = useState(false);

  // Product Detail State
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isProductDetailOpen, setIsProductDetailOpen] = useState(false);

  // Lightbox State
  const [lightboxImage, setLightboxImage] = useState<string | null>(null);

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('pos_orders');
    return saved ? JSON.parse(saved) : [];
  });

  // Held Orders State
  const [heldOrders, setHeldOrders] = useState<HeldOrder[]>(() => {
    const saved = localStorage.getItem('pos_held_orders');
    return saved ? JSON.parse(saved) : [];
  });
  const [isHeldOrdersOpen, setIsHeldOrdersOpen] = useState(false);

  // Favorites State
  const [favoriteIds, setFavoriteIds] = useState<Set<number>>(() => {
    const saved = localStorage.getItem('pos_favorites');
    return saved ? new Set(JSON.parse(saved)) : new Set();
  });

  const [settings, setSettings] = useState<WCSettings>(() => {
    const saved = localStorage.getItem('wc_settings');
    return saved ? JSON.parse(saved) : {
      url: '',
      consumerKey: '',
      consumerSecret: '',
      useMockData: true // Default to mock data for instant usability
    };
  });

  // --- Effects ---

  // Auto-fetch Secrets from GCP on startup if configured
  useEffect(() => {
    const initApp = async () => {
      setIsLoading(true);
      let effectiveSettings = settings;

      // Check if we have GCP credentials to fetch secrets
      if (!settings.useMockData && settings.gcpAccessToken && settings.gcpProjectId) {
        setInitMsg("正在從 Google Secret Manager 讀取金鑰...");
        try {
          const keyName = settings.secretKeyName || 'woocommerce-pos-key';
          const secretName = settings.secretSecretName || 'woocommerce-pos-secret';

          const [fetchedKey, fetchedSecret] = await Promise.all([
             getSecretValue(settings.gcpProjectId, keyName, settings.gcpAccessToken),
             getSecretValue(settings.gcpProjectId, secretName, settings.gcpAccessToken)
          ]);

          // Update settings in memory and state (but maybe not save to localstorage to keep it dynamic? 
          // For now we update state so fetchProducts uses it)
          effectiveSettings = {
            ...settings,
            consumerKey: fetchedKey,
            consumerSecret: fetchedSecret
          };
          setSettings(effectiveSettings); // Update React state
          setInitMsg("金鑰讀取成功，正在連線商店...");
        } catch (err) {
          console.error("Auto-fetch secrets failed:", err);
          setError("無法從 Secret Manager 讀取金鑰，請檢查 Access Token 是否過期。");
          setInitMsg(null);
          setIsSettingsOpen(true); // Open settings to let user fix it
          setIsLoading(false);
          return; // Stop here
        }
      }

      // Proceed to load data
      loadData(effectiveSettings);
    };

    initApp();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount (or if we wanted to run on settings change, we'd add it, but this is startup logic)

  // Persist Favorites
  useEffect(() => {
    localStorage.setItem('pos_favorites', JSON.stringify(Array.from(favoriteIds)));
  }, [favoriteIds]);

  // Persist Orders
  useEffect(() => {
    localStorage.setItem('pos_orders', JSON.stringify(orders));
  }, [orders]);

  // Persist Held Orders
  useEffect(() => {
    localStorage.setItem('pos_held_orders', JSON.stringify(heldOrders));
  }, [heldOrders]);

  const loadData = async (currentSettings: WCSettings) => {
    setIsLoading(true);
    setError(null);
    setInitMsg("正在載入商品...");
    try {
      const [cats, prods, custs] = await Promise.all([
        fetchCategories(currentSettings),
        fetchProducts(currentSettings),
        fetchCustomers(currentSettings)
      ]);
      setCategories(cats);
      setProducts(prods);
      setCustomers(custs);
      setInitMsg(null);
    } catch (err: any) {
      setError('載入失敗，請檢查 WooCommerce 設定或連線。');
      // Auto-open settings if real connection fails
      if (!currentSettings.useMockData) {
          setIsSettingsOpen(true);
      }
    } finally {
      setIsLoading(false);
    }
  };

  // --- Handlers ---
  const saveSettings = (newSettings: WCSettings) => {
    setSettings(newSettings);
    localStorage.setItem('wc_settings', JSON.stringify(newSettings));
    setSelectedCategory(null);
    // Reload data with new settings
    loadData(newSettings);
  };

  // Handle clicking on a product card
  const handleProductClick = (product: Product) => {
    // If product has variations or attributes (is variable), open detail modal
    if (product.type === 'variable' && (product.variations?.length || 0) > 0 || product.attributes.length > 0) {
      setSelectedProduct(product);
      setIsProductDetailOpen(true);
    } else {
      // If simple product, add directly to cart
      addToCart(product);
    }
  };

  const addToCart = (product: Product, variation?: ProductVariation) => {
    setCart(prev => {
      // Determine if item exists based on product ID AND variation ID (if applicable)
      const existing = prev.find(item => {
        if (variation) {
          return item.id === product.id && item.selectedVariation?.id === variation.id;
        }
        return item.id === product.id && !item.selectedVariation;
      });

      if (existing) {
        return prev.map(item => {
           // Match logic must be same as above
           const isMatch = variation 
             ? item.id === product.id && item.selectedVariation?.id === variation.id
             : item.id === product.id && !item.selectedVariation;

           return isMatch ? { ...item, quantity: item.quantity + 1 } : item;
        });
      }

      // New Item
      return [...prev, { 
        ...product, 
        quantity: 1, 
        discount: 0, 
        note: '', 
        selectedVariation: variation ? {
          id: variation.id,
          price: variation.price,
          attributes: variation.attributes
        } : undefined
      }];
    });
  };

  const updateQuantity = (id: number, delta: number) => {
    setCart(prev => prev.map(item => {
      // Note: This matches ID-based. In production, use unique cart item IDs for perfect variation handling.
      if (item.id === id) { 
        return { ...item, quantity: Math.max(0, item.quantity + delta) };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const updateItemDetails = (id: number, updates: Partial<CartItem>) => {
    setCart(prev => prev.map(item => 
      item.id === id ? { ...item, ...updates } : item
    ));
  };

  const removeFromCart = (id: number) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const clearCart = () => {
    setCart([]);
    setSelectedCustomer(null);
    setOrderDiscount(0);
  };

  const toggleFavorite = (id: number) => {
    setFavoriteIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  // --- Hold Order Logic ---
  const handleHoldOrder = () => {
    if (cart.length === 0) return;

    let sub = 0;
    let itemDisc = 0;
    cart.forEach(item => {
       const price = item.selectedVariation ? parseFloat(item.selectedVariation.price) : parseFloat(item.price);
       sub += price * item.quantity;
       itemDisc += item.discount || 0;
    });
    const total = Math.max(0, sub - itemDisc - orderDiscount);

    const newHeldOrder: HeldOrder = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      customer: selectedCustomer,
      items: [...cart],
      orderDiscount: orderDiscount,
      total: total
    };

    setHeldOrders(prev => [...prev, newHeldOrder]);
    clearCart();
  };

  const handleRestoreHeldOrder = (order: HeldOrder) => {
    setCart(order.items);
    setSelectedCustomer(order.customer);
    setOrderDiscount(order.orderDiscount);

    setHeldOrders(prev => prev.filter(o => o.id !== order.id));
    setIsHeldOrdersOpen(false);
  };

  const handleDeleteHeldOrder = (id: string) => {
    setHeldOrders(prev => prev.filter(o => o.id !== id));
  };

  // --- Checkout Logic (Optimistic UI) ---
  const handleCheckoutRequest = (summary: OrderSummary) => {
    setCheckoutSummary(summary);
    setIsCheckoutOpen(true);
  };

  const handleConfirmOrder = async (status: OrderStatus) => {
    if (!checkoutSummary) return;

    try {
      // 1. Prepare Data
      // Map to WooCommerce Order Structure
      const lineItems = cart.map(item => {
        const unitPrice = item.selectedVariation ? parseFloat(item.selectedVariation.price) : parseFloat(item.price);
        const lineTotalBeforeDiscount = unitPrice * item.quantity;
        const discountAmount = item.discount || 0;
        const finalLineTotal = Math.max(0, lineTotalBeforeDiscount - discountAmount);

        // Build explicit payload for line item
        const lineItemPayload: any = {
          product_id: item.id,
          quantity: item.quantity,
          total: finalLineTotal.toFixed(2),
        };

        if (item.selectedVariation?.id) {
          lineItemPayload.variation_id = item.selectedVariation.id;
        }

        const meta_data = [];
        if (item.note) {
          meta_data.push({ key: 'note', value: item.note });
        }

        if (meta_data.length > 0) {
            lineItemPayload.meta_data = meta_data;
        }

        return lineItemPayload;
      });

      const feeLines = [];
      if (orderDiscount > 0) {
        feeLines.push({
          name: '整單折扣 (Order Discount)',
          total: (-orderDiscount).toFixed(2),
          tax_class: 'zero-rate'
        });
      }

      const customerId = selectedCustomer && selectedCustomer.id > 0 ? selectedCustomer.id : 0;

      const billingData = {
        first_name: selectedCustomer?.first_name || 'Guest',
        last_name: selectedCustomer?.last_name || 'User',
        address_1: selectedCustomer?.address || 'Store Walk-in',
        address_2: '',
        city: 'Taipei',
        state: 'TPE',
        postcode: '100',
        country: 'TW',
        email: selectedCustomer?.email || 'pos-guest@example.com',
        phone: selectedCustomer?.phone || '0900000000'
      };

      const orderData = {
        payment_method: 'other', 
        payment_method_title: 'POS Payment',
        set_paid: status === 'completed' || status === 'processing',
        status: status,
        customer_id: customerId,
        billing: billingData,
        line_items: lineItems,
        fee_lines: feeLines,
      };

      // 2. Optimistic Update (Update UI Immediately)
      const tempId = `local-${Date.now()}`;
      const newOrder: Order = {
        id: tempId,
        date: new Date().toISOString(),
        customer: selectedCustomer,
        items: [...cart],
        summary: checkoutSummary,
        status: status
      };

      // Add to history instantly with temp ID
      setOrders(prev => [newOrder, ...prev]);

      // Clear UI instantly
      clearCart();
      setIsCheckoutOpen(false);
      setCheckoutSummary(null);

      // 3. Background Sync (Fire and Forget from UI perspective)
      // This runs in background. If successful, it updates the order ID.
      createOrder(settings, orderData)
        .then((createdOrder) => {
          setOrders(prev => prev.map(o => 
            o.id === tempId ? { ...o, id: createdOrder.id.toString(), status: createdOrder.status || status } : o
          ));
        })
        .catch((err) => {
          console.error("Background Order Sync Failed:", err);
          // Mark order as failed in history so user knows something went wrong
          setOrders(prev => prev.map(o => 
            o.id === tempId ? { ...o, status: 'failed' } : o
          ));
          // Optionally push a toast notification here
        });

    } catch (err: any) {
      // Logic error before API call (e.g. payload construction), alert user
      console.error("Order processing error", err);
      alert(`訂單處理錯誤: ${err.message}`);
    }
  };

  const handleUpdateOrderStatus = (orderId: string, newStatus: OrderStatus) => {
    setOrders(prev => prev.map(order => 
      order.id === orderId ? { ...order, status: newStatus } : order
    ));
    // In a real app, you would also call an API to update the order status in WooCommerce here.
  };

  // --- Filtering Logic ---
  const filteredProducts = useMemo(() => {
    let result = products;

    if (searchTerm) {
      result = result.filter(p => 
        p.name.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (selectedCategory !== null) {
      if (selectedCategory === FAVORITES_ID) {
        result = result.filter(p => favoriteIds.has(p.id));
      } else {
        const getDescendantIds = (parentId: number): number[] => {
            const children = categories.filter(c => c.parent === parentId);
            let ids = children.map(c => c.id);
            children.forEach(c => {
                ids = [...ids, ...getDescendantIds(c.id)];
            });
            return ids;
        };

        const targetCategoryIds = [selectedCategory, ...getDescendantIds(selectedCategory)];

        result = result.filter(p => 
          p.categories.some(c => targetCategoryIds.includes(c.id))
        );
      }
    }

    return result;
  }, [products, searchTerm, selectedCategory, favoriteIds, categories]);

  // --- Render ---
  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden font-sans text-gray-900">

      {/* Left Side - Main Content */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* Top Header */}
        <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm z-10">
          <div className="flex items-center space-x-4">
            <div className="bg-indigo-600 text-white p-2 rounded-lg">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" />
                </svg>
            </div>
            <h1 className="text-2xl font-bold text-gray-800 tracking-tight">WooPOS</h1>
          </div>

          {/* Search Bar */}
          <div className="flex-1 max-w-xl mx-8 relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>
            <input
              type="text"
              placeholder="搜尋商品..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 rounded-full bg-gray-100 border-transparent focus:bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none"
            />
          </div>

          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setIsHistoryOpen(true)}
              className="p-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors flex items-center gap-1 px-3"
              title="歷史訂單"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span className="hidden sm:inline font-medium text-sm">歷史訂單</span>
            </button>

            <button 
              onClick={() => setIsSettingsOpen(true)}
              className="p-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors"
              title="設定"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-6">
          <div className="mb-6">
            <CategoryFilter 
              categories={categories} 
              selectedId={selectedCategory} 
              onSelect={setSelectedCategory} 
            />
          </div>

          {error && (
            <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-6 flex items-center justify-between">
              <span>{error}</span>
              <button 
                onClick={() => setIsSettingsOpen(true)}
                className="text-sm underline hover:text-red-800"
              >
                開啟設定
              </button>
            </div>
          )}

          {initMsg && (
             <div className="flex items-center justify-center p-4 bg-blue-50 text-blue-700 rounded-lg mb-6 border border-blue-100">
               <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-blue-700" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
               </svg>
               {initMsg}
             </div>
          )}

          {isLoading ? (
            <div className="flex items-center justify-center h-64">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
            </div>
          ) : (
            <>
              {selectedCategory === FAVORITES_ID && (
                <div className="mb-4 text-xl font-bold text-gray-800 flex items-center">
                   <span className="mr-2 text-red-500">♥</span> 我的最愛 ({filteredProducts.length})
                </div>
              )}

              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                {filteredProducts.map(product => (
                  <ProductCard 
                    key={product.id} 
                    product={product}
                    isFavorite={favoriteIds.has(product.id)}
                    onToggleFavorite={toggleFavorite}
                    onClick={handleProductClick}
                    onZoom={(img) => setLightboxImage(img)}
                  />
                ))}
              </div>
            </>
          )}

          {!isLoading && filteredProducts.length === 0 && (
             <div className="flex flex-col items-center justify-center h-64 text-gray-500">
               {selectedCategory === FAVORITES_ID ? (
                 <>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                    </svg>
                    <p className="text-lg">尚無最愛商品</p>
                    <p className="text-sm">點擊商品卡片右上角的愛心即可加入</p>
                 </>
               ) : (
                 <>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                    </svg>
                    <p className="text-lg">沒有找到相關商品</p>
                    <p className="text-sm">請嘗試調整搜尋或篩選條件</p>
                 </>
               )}
             </div>
          )}
        </div>
      </div>

      {/* Right Side - Cart */}
      <div className="w-96 bg-white shadow-xl border-l border-gray-200 z-20 flex-shrink-0">
        <Cart 
          items={cart} 
          customer={selectedCustomer}
          orderDiscount={orderDiscount}
          heldOrdersCount={heldOrders.length}
          onSelectCustomer={() => setIsCustomerModalOpen(true)}
          onUpdateQuantity={updateQuantity} 
          onRemove={removeFromCart}
          onUpdateItem={updateItemDetails}
          onClear={clearCart}
          onSetOrderDiscount={setOrderDiscount}
          onCheckout={handleCheckoutRequest} 
          onHoldOrder={handleHoldOrder}
          onOpenHeldOrders={() => setIsHeldOrdersOpen(true)}
        />
      </div>

      {/* Modals & Overlays */}
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={settings}
        onSave={saveSettings}
      />

      <CheckoutModal
        isOpen={isCheckoutOpen}
        onClose={() => setIsCheckoutOpen(false)}
        items={cart}
        customer={selectedCustomer}
        summary={checkoutSummary}
        onConfirm={handleConfirmOrder}
      />

      <OrderHistory
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        orders={orders}
        onUpdateStatus={handleUpdateOrderStatus}
      />

      <CustomerSelectionModal
        isOpen={isCustomerModalOpen}
        onClose={() => setIsCustomerModalOpen(false)}
        customers={customers}
        onSelect={setSelectedCustomer}
      />

      <HeldOrdersModal
        isOpen={isHeldOrdersOpen}
        onClose={() => setIsHeldOrdersOpen(false)}
        heldOrders={heldOrders}
        onRestore={handleRestoreHeldOrder}
        onDelete={handleDeleteHeldOrder}
      />

      <ProductDetailModal
        isOpen={isProductDetailOpen}
        onClose={() => setIsProductDetailOpen(false)}
        product={selectedProduct}
        settings={settings}
        onAddToCart={addToCart}
      />

      <ImageLightbox
        isOpen={!!lightboxImage}
        onClose={() => setLightboxImage(null)}
        imageSrc={lightboxImage}
      />

      <AIAssistant products={products} cart={cart} />

    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Product, ProductVariation, WCSettings } from '../types';
import { fetchVariations } from '../services/wooService';

interface ProductDetailModalProps {
  isOpen: boolean;
  onClose: () => void;
  product: Product | null;
  settings?: WCSettings; // Add settings to fetch variations
  onAddToCart: (product: Product, variation?: ProductVariation) => void;
}

const ProductDetailModal: React.FC<ProductDetailModalProps> = ({ isOpen, onClose, product, settings, onAddToCart }) => {
  const [selectedAttributes, setSelectedAttributes] = useState<Record<string, string>>({});
  const [currentVariation, setCurrentVariation] = useState<ProductVariation | null>(null);
  const [variations, setVariations] = useState<ProductVariation[]>([]);
  const [loadingVariations, setLoadingVariations] = useState(false);

  useEffect(() => {
    if (product) {
      setSelectedAttributes({});
      setCurrentVariation(null);

      // Initial variations from product data (mock data usually has them)
      let initialVariations = product.variations || [];
      setVariations(initialVariations);

      // Check if we need to and CAN fetch variations
      const shouldFetch = 
        product.type === 'variable' && 
        initialVariations.length === 0 && 
        settings && 
        !settings.useMockData && 
        settings.url && 
        settings.consumerKey;

      if (shouldFetch) {
        setLoadingVariations(true);
        fetchVariations(settings!, product.id)
          .then(data => {
            if (data && data.length > 0) {
              setVariations(data);
            }
          })
          .catch(err => {
             // Error handled in service, just stop loading
             console.debug("Variation fetch skipped or failed", err);
          })
          .finally(() => setLoadingVariations(false));
      }
    }
  }, [product, settings]);

  // Determine current variation when attributes or variations change
  useEffect(() => {
    if (!product || product.type !== 'variable') return;

    const attributes = product.attributes || [];

    // Check if all attributes are selected
    const allSelected = attributes.every(attr => selectedAttributes[attr.name]);

    if (allSelected && variations.length > 0) {
      // Logic to find matching variation
      // Note: We try to match loosely in case attribute names differ (e.g. Slug vs Name)
      const match = variations.find(v => 
        v.attributes.every(va => {
           // Direct match
           if (selectedAttributes[va.name] === va.option) return true;
           // Try matching keys if names are slightly different (e.g. Size vs pa_size)
           // For simplicity we stick to direct name match from the dropdown logic
           return false;
        })
      );
      setCurrentVariation(match || null);
    } else {
      setCurrentVariation(null);
    }
  }, [selectedAttributes, variations, product]);

  if (!isOpen || !product) return null;

  const handleAttributeSelect = (name: string, option: string) => {
    setSelectedAttributes(prev => ({ ...prev, [name]: option }));
  };

  const handleAddToCart = () => {
    const isVariable = product.type === 'variable' || (product.attributes && product.attributes.length > 0);

    if (isVariable) {
      if (currentVariation) {
        // Perfect match with a known variation
        onAddToCart(product, currentVariation);
        onClose();
      } else {
        // Fallback: No variation object found (e.g. API didn't return them), but user selected attributes.
        // We construct a synthetic variation to allow the cart to function.
        // Important: If we failed to fetch variations, this uses base price, which might be incorrect.
        const allAttributesSelected = product.attributes.every(attr => selectedAttributes[attr.name]);
        if (allAttributesSelected) {
           const syntheticVariation: ProductVariation = {
             id: Date.now(), // Generate a temp ID
             price: product.price,
             regular_price: product.regular_price,
             sale_price: product.sale_price,
             stock_status: product.stock_status,
             attributes: Object.entries(selectedAttributes).map(([name, option]) => ({ name, option: option as string }))
           };
           onAddToCart(product, syntheticVariation);
           onClose();
        }
      }
    } else {
      // Simple product
      onAddToCart(product);
      onClose();
    }
  };

  // Pricing Logic
  const currentPrice = currentVariation ? currentVariation.price : product.price;
  const currentRegularPrice = currentVariation ? currentVariation.regular_price : product.regular_price;
  const isSale = currentRegularPrice !== currentPrice && currentRegularPrice !== '';

  // Validation Logic
  const isVariable = product.type === 'variable' || (product.attributes && product.attributes.length > 0);
  const allAttributesSelected = isVariable && product.attributes.every(attr => selectedAttributes[attr.name]);

  // Enable button if:
  // 1. Not a variable product
  // 2. Variable product AND a variation is matched
  // 3. Variable product AND all attributes selected (fallback)
  // Disable if loading variations
  const isReadyToAdd = !loadingVariations && (!isVariable || (currentVariation || allAttributesSelected));

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-70 backdrop-blur-sm animate-fade-in p-4" onClick={onClose}>
      <div 
        className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col md:flex-row max-h-[90vh]" 
        onClick={e => e.stopPropagation()}
      >

        {/* Image Section */}
        <div className="w-full md:w-1/2 bg-gray-100 relative h-64 md:h-auto border-b md:border-b-0 md:border-r border-gray-100 flex-shrink-0">
          <img 
            src={product.images[0]?.src || 'https://picsum.photos/400'} 
            alt={product.name} 
            className="w-full h-full object-cover"
            decoding="async"
          />
          {isSale && (
             <div className="absolute top-4 left-4 bg-red-500 text-white text-sm font-bold px-3 py-1 rounded-full shadow-md">
               特價中
             </div>
          )}
        </div>

        {/* Details Section */}
        <div className="w-full md:w-1/2 p-6 md:p-8 flex flex-col overflow-y-auto">
          <div className="flex justify-between items-start mb-4">
            <h2 className="text-xl md:text-2xl font-bold text-gray-900 leading-tight pr-4">{product.name}</h2>
            <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full text-gray-500 transition-colors flex-shrink-0">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
               </svg>
            </button>
          </div>

          <div className="mb-6">
             <div className="flex items-end gap-3">
               <span className="text-3xl font-bold text-indigo-600">${Math.round(parseFloat(currentPrice))}</span>
               {isSale && (
                 <span className="text-lg text-gray-400 line-through mb-1">${Math.round(parseFloat(currentRegularPrice))}</span>
               )}
             </div>
          </div>

          <div className="prose prose-sm text-gray-600 mb-6 flex-1">
             <p>{product.description ? product.description.replace(/<[^>]*>?/gm, '') : '暫無商品描述。'}</p>
          </div>

          {/* Attributes Selection */}
          {isVariable && (
            <div className="space-y-5 mb-8">
              {loadingVariations && (
                 <div className="flex items-center text-indigo-600 text-sm mb-2">
                    <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-indigo-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    正在載入規格價格...
                 </div>
              )}
              {product.attributes.map(attr => (
                <div key={attr.id}>
                   <h3 className="text-xs font-bold text-gray-800 uppercase tracking-wide mb-2">{attr.name}</h3>
                   <div className="flex flex-wrap gap-2">
                     {attr.options.map(option => {
                       const isSelected = selectedAttributes[attr.name] === option;
                       return (
                         <button
                           key={option}
                           onClick={() => handleAttributeSelect(attr.name, option)}
                           className={`px-4 py-2 rounded-lg border text-sm font-medium transition-all transform active:scale-95 ${
                             isSelected 
                               ? 'border-indigo-600 bg-indigo-600 text-white shadow-md' 
                               : 'border-gray-200 text-gray-700 hover:border-indigo-400 hover:bg-indigo-50'
                           }`}
                         >
                           {option}
                         </button>
                       );
                     })}
                   </div>
                </div>
              ))}
            </div>
          )}

          <div className="mt-auto pt-4 border-t border-gray-100">
            <button
              onClick={handleAddToCart}
              disabled={!isReadyToAdd}
              className={`w-full py-3.5 px-4 font-bold rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 transform active:scale-[0.98] ${
                 !isReadyToAdd 
                  ? 'bg-gray-300 text-gray-500 cursor-not-allowed shadow-none'
                  : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-200'
              }`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" />
              </svg>
              {!isReadyToAdd ? '請選擇商品規格' : '加入購物車'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetailModal;

import React, { useState, useEffect, useMemo } from 'react';
import { Product, Category, CartItem, WCSettings, Order, OrderSummary, Customer, OrderStatus, HeldOrder, ProductVariation } from './types';
import { fetchProducts, fetchCategories, fetchCustomers, createOrder } from './services/wooService';
import { getSecretValue } from './services/secretManagerService';
import ProductCard from './components/ProductCard';
import Cart from './components/Cart';
import CategoryFilter, { FAVORITES_ID } from './components/CategoryFilter';
import SettingsModal from './components/SettingsModal';
import AIAssistant from './components/AIAssistant';
import CheckoutModal from './components/CheckoutModal';
import OrderHistory from './components/OrderHistory';
import CustomerSelectionModal from './components/CustomerSelectionModal';
import HeldOrdersModal from './components/HeldOrdersModal';
import ProductDetailModal from './components/ProductDetailModal';
import ImageLightbox from './components/ImageLightbox';

const App: React.FC = () => {
  // --- State ---
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<number | null>(null);
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
  const [orderDiscount, setOrderDiscount] = useState<number>(0); // Lifted from Cart
  const [searchTerm, setSearchTerm] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [initMsg, setInitMsg] = useState<string | null>(null);

  // Checkout & History State
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [checkoutSummary, setCheckoutSummary] = useState<OrderSummary | null>(null);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isCustomerModalOpen, setIsCustomerModalOpen] = useState(false);

  // Product Detail State
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isProductDetailOpen, setIsProductDetailOpen] = useState(false);

  // Lightbox State
  const [lightboxImage, setLightboxImage] = useState<string | null>(null);

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('pos_orders');
    return saved ? JSON.parse(saved) : [];
  });

  // Held Orders State
  const [heldOrders, setHeldOrders] = useState<HeldOrder[]>(() => {
    const saved = localStorage.getItem('pos_held_orders');
    return saved ? JSON.parse(saved) : [];
  });
  const [isHeldOrdersOpen, setIsHeldOrdersOpen] = useState(false);

  // Favorites State
  const [favoriteIds, setFavoriteIds] = useState<Set<number>>(() => {
    const saved = localStorage.getItem('pos_favorites');
    return saved ? new Set(JSON.parse(saved)) : new Set();
  });

  const [settings, setSettings] = useState<WCSettings>(() => {
    const saved = localStorage.getItem('wc_settings');
    return saved ? JSON.parse(saved) : {
      url: '',
      consumerKey: '',
      consumerSecret: '',
      useMockData: true // Default to mock data for instant usability
    };
  });

  // --- Effects ---

  // Auto-fetch Secrets from GCP on startup if configured
  useEffect(() => {
    const initApp = async () => {
      setIsLoading(true);
      let effectiveSettings = settings;

      // Check if we have GCP credentials to fetch secrets
      if (!settings.useMockData && settings.gcpAccessToken && settings.gcpProjectId) {
        setInitMsg("正在從 Google Secret Manager 讀取金鑰...");
        try {
          const keyName = settings.secretKeyName || 'woocommerce-pos-key';
          const secretName = settings.secretSecretName || 'woocommerce-pos-secret';

          const [fetchedKey, fetchedSecret] = await Promise.all([
             getSecretValue(settings.gcpProjectId, keyName, settings.gcpAccessToken),
             getSecretValue(settings.gcpProjectId, secretName, settings.gcpAccessToken)
          ]);

          // Update settings in memory and state (but maybe not save to localstorage to keep it dynamic? 
          // For now we update state so fetchProducts uses it)
          effectiveSettings = {
            ...settings,
            consumerKey: fetchedKey,
            consumerSecret: fetchedSecret
          };
          setSettings(effectiveSettings); // Update React state
          setInitMsg("金鑰讀取成功，正在連線商店...");
        } catch (err) {
          console.error("Auto-fetch secrets failed:", err);
          setError("無法從 Secret Manager 讀取金鑰，請檢查 Access Token 是否過期。");
          setInitMsg(null);
          setIsSettingsOpen(true); // Open settings to let user fix it
          setIsLoading(false);
          return; // Stop here
        }
      }

      // Proceed to load data
      loadData(effectiveSettings);
    };

    initApp();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount (or if we wanted to run on settings change, we'd add it, but this is startup logic)

  // Persist Favorites
  useEffect(() => {
    localStorage.setItem('pos_favorites', JSON.stringify(Array.from(favoriteIds)));
  }, [favoriteIds]);

  // Persist Orders
  useEffect(() => {
    localStorage.setItem('pos_orders', JSON.stringify(orders));
  }, [orders]);

  // Persist Held Orders
  useEffect(() => {
    localStorage.setItem('pos_held_orders', JSON.stringify(heldOrders));
  }, [heldOrders]);

  const loadData = async (currentSettings: WCSettings) => {
    setIsLoading(true);
    setError(null);
    setInitMsg("正在載入商品...");
    try {
      const [cats, prods, custs] = await Promise.all([
        fetchCategories(currentSettings),
        fetchProducts(currentSettings),
        fetchCustomers(currentSettings)
      ]);
      setCategories(cats);
      setProducts(prods);
      setCustomers(custs);
      setInitMsg(null);
    } catch (err: any) {
      setError('載入失敗，請檢查 WooCommerce 設定或連線。');
      // Auto-open settings if real connection fails
      if (!currentSettings.useMockData) {
          setIsSettingsOpen(true);
      }
    } finally {
      setIsLoading(false);
    }
  };

  // --- Handlers ---
  const saveSettings = (newSettings: WCSettings) => {
    setSettings(newSettings);
    localStorage.setItem('wc_settings', JSON.stringify(newSettings));
    setSelectedCategory(null);
    // Reload data with new settings
    loadData(newSettings);
  };

  // Handle clicking on a product card
  const handleProductClick = (product: Product) => {
    // If product has variations or attributes (is variable), open detail modal
    if (product.type === 'variable' && (product.variations?.length || 0) > 0 || product.attributes.length > 0) {
      setSelectedProduct(product);
      setIsProductDetailOpen(true);
    } else {
      // If simple product, add directly to cart
      addToCart(product);
    }
  };

  const addToCart = (product: Product, variation?: ProductVariation) => {
    setCart(prev => {
      // Determine if item exists based on product ID AND variation ID (if applicable)
      const existing = prev.find(item => {
        if (variation) {
          return item.id === product.id && item.selectedVariation?.id === variation.id;
        }
        return item.id === product.id && !item.selectedVariation;
      });

      if (existing) {
        return prev.map(item => {
           // Match logic must be same as above
           const isMatch = variation 
             ? item.id === product.id && item.selectedVariation?.id === variation.id
             : item.id === product.id && !item.selectedVariation;

           return isMatch ? { ...item, quantity: item.quantity + 1 } : item;
        });
      }

      // New Item
      return [...prev, { 
        ...product, 
        quantity: 1, 
        discount: 0, 
        note: '', 
        selectedVariation: variation ? {
          id: variation.id,
          price: variation.price,
          attributes: variation.attributes
        } : undefined
      }];
    });
  };

  const updateQuantity = (id: number, delta: number) => {
    setCart(prev => prev.map(item => {
      // Note: This matches ID-based. In production, use unique cart item IDs for perfect variation handling.
      if (item.id === id) { 
        return { ...item, quantity: Math.max(0, item.quantity + delta) };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const updateItemDetails = (id: number, updates: Partial<CartItem>) => {
    setCart(prev => prev.map(item => 
      item.id === id ? { ...item, ...updates } : item
    ));
  };

  const removeFromCart = (id: number) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const clearCart = () => {
    setCart([]);
    setSelectedCustomer(null);
    setOrderDiscount(0);
  };

  const toggleFavorite = (id: number) => {
    setFavoriteIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  // --- Hold Order Logic ---
  const handleHoldOrder = () => {
    if (cart.length === 0) return;

    let sub = 0;
    let itemDisc = 0;
    cart.forEach(item => {
       const price = item.selectedVariation ? parseFloat(item.selectedVariation.price) : parseFloat(item.price);
       sub += price * item.quantity;
       itemDisc += item.discount || 0;
    });
    const total = Math.max(0, sub - itemDisc - orderDiscount);

    const newHeldOrder: HeldOrder = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      customer: selectedCustomer,
      items: [...cart],
      orderDiscount: orderDiscount,
      total: total
    };

    setHeldOrders(prev => [...prev, newHeldOrder]);
    clearCart();
  };

  const handleRestoreHeldOrder = (order: HeldOrder) => {
    setCart(order.items);
    setSelectedCustomer(order.customer);
    setOrderDiscount(order.orderDiscount);

    setHeldOrders(prev => prev.filter(o => o.id !== order.id));
    setIsHeldOrdersOpen(false);
  };

  const handleDeleteHeldOrder = (id: string) => {
    setHeldOrders(prev => prev.filter(o => o.id !== id));
  };

  // --- Checkout Logic (Optimistic UI) ---
  const handleCheckoutRequest = (summary: OrderSummary) => {
    setCheckoutSummary(summary);
    setIsCheckoutOpen(true);
  };

  const handleConfirmOrder = async (status: OrderStatus) => {
    if (!checkoutSummary) return;

    // 1. Snapshot critical data needed for API
    // We must copy these because we will clear the state immediately for the next user.
    const currentCart = [...cart];
    const currentCustomer = selectedCustomer;
    const currentDiscount = orderDiscount;
    const currentSummary = checkoutSummary;

    // 2. Optimistic Update (Update UI Immediately)
    // Create a temporary ID starting with 'local-'
    const tempId = `local-${Date.now()}`;
    const newOrder: Order = {
      id: tempId,
      date: new Date().toISOString(),
      customer: currentCustomer,
      items: currentCart,
      summary: currentSummary,
      status: status // This will be the initial status in history
    };

    // Add to history instantly with temp ID
    setOrders(prev => [newOrder, ...prev]);

    // Clear UI instantly so the user can continue working
    clearCart();
    setIsCheckoutOpen(false);
    setCheckoutSummary(null);

    // 3. Background Processing
    // This runs without blocking the UI
    try {
      // Map to WooCommerce Order Structure
      const lineItems = currentCart.map(item => {
        const unitPrice = item.selectedVariation ? parseFloat(item.selectedVariation.price) : parseFloat(item.price);
        const lineTotalBeforeDiscount = unitPrice * item.quantity;
        const discountAmount = item.discount || 0;
        const finalLineTotal = Math.max(0, lineTotalBeforeDiscount - discountAmount);

        // Build explicit payload for line item
        const lineItemPayload: any = {
          product_id: item.id,
          quantity: item.quantity,
          total: finalLineTotal.toFixed(2),
        };

        if (item.selectedVariation?.id) {
          lineItemPayload.variation_id = item.selectedVariation.id;
        }

        const meta_data = [];
        if (item.note) {
          meta_data.push({ key: 'note', value: item.note });
        }

        if (meta_data.length > 0) {
            lineItemPayload.meta_data = meta_data;
        }

        return lineItemPayload;
      });

      const feeLines = [];
      if (currentDiscount > 0) {
        feeLines.push({
          name: '整單折扣 (Order Discount)',
          total: (-currentDiscount).toFixed(2),
          tax_class: 'zero-rate'
        });
      }

      const customerId = currentCustomer && currentCustomer.id > 0 ? currentCustomer.id : 0;

      const billingData = {
        first_name: currentCustomer?.first_name || 'Guest',
        last_name: currentCustomer?.last_name || 'User',
        address_1: currentCustomer?.address || 'Store Walk-in',
        address_2: '',
        city: 'Taipei',
        state: 'TPE',
        postcode: '100',
        country: 'TW',
        email: currentCustomer?.email || 'pos-guest@example.com',
        phone: currentCustomer?.phone || '0900000000'
      };

      const orderData = {
        payment_method: 'other', 
        payment_method_title: 'POS Payment',
        set_paid: status === 'completed' || status === 'processing',
        status: status,
        customer_id: customerId,
        billing: billingData,
        line_items: lineItems,
        fee_lines: feeLines,
      };

      // Perform API Call
      const createdOrder = await createOrder(settings, orderData);

      // On Success: Update the temporary order with the real ID from WooCommerce
      setOrders(prev => prev.map(o => 
        o.id === tempId ? { ...o, id: createdOrder.id.toString(), status: createdOrder.status || status } : o
      ));

    } catch (err: any) {
      console.error("Background Order Sync Failed:", err);
      // On Failure: Mark order as failed in history
      setOrders(prev => prev.map(o => 
        o.id === tempId ? { ...o, status: 'failed' } : o
      ));

      // Alert the user as requested
      // We use a slight timeout to ensure it doesn't conflict with other UI transitions if any
      setTimeout(() => {
        alert(`⚠️ 訂單同步失敗！\n\n原因: ${err.message}\n\n該訂單已在歷史紀錄中標記為「失敗」，請檢查網路連線或稍後重試。`);
      }, 500);
    }
  };

  const handleUpdateOrderStatus = (orderId: string, newStatus: OrderStatus) => {
    setOrders(prev => prev.map(order => 
      order.id === orderId ? { ...order, status: newStatus } : order
    ));
    // In a real app, you would also call an API to update the order status in WooCommerce here.
  };

  // --- Filtering Logic ---
  const filteredProducts = useMemo(() => {
    let result = products;

    if (searchTerm) {
      result = result.filter(p => 
        p.name.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (selectedCategory !== null) {
      if (selectedCategory === FAVORITES_ID) {
        result = result.filter(p => favoriteIds.has(p.id));
      } else {
        const getDescendantIds = (parentId: number): number[] => {
            const children = categories.filter(c => c.parent === parentId);
            let ids = children.map(c => c.id);
            children.forEach(c => {
                ids = [...ids, ...getDescendantIds(c.id)];
            });
            return ids;
        };

        const targetCategoryIds = [selectedCategory, ...getDescendantIds(selectedCategory)];

        result = result.filter(p => 
          p.categories.some(c => targetCategoryIds.includes(c.id))
        );
      }
    }

    return result;
  }, [products, searchTerm, selectedCategory, favoriteIds, categories]);

  // --- Render ---
  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden font-sans text-gray-900">

      {/* Left Side - Main Content */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* Top Header */}
        <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm z-10">
          <div className="flex items-center space-x-4">
            <div className="bg-indigo-600 text-white p-2 rounded-lg">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" />
                </svg>
            </div>
            <h1 className="text-2xl font-bold text-gray-800 tracking-tight">WooPOS</h1>
          </div>

          {/* Search Bar */}
          <div className="flex-1 max-w-xl mx-8 relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>
            <input
              type="text"
              placeholder="搜尋商品..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 rounded-full bg-gray-100 border-transparent focus:bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none"
            />
          </div>

          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setIsHistoryOpen(true)}
              className="p-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors flex items-center gap-1 px-3"
              title="歷史訂單"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span className="hidden sm:inline font-medium text-sm">歷史訂單</span>
            </button>

            <button 
              onClick={() => setIsSettingsOpen(true)}
              className="p-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors"
              title="設定"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-6">
          <div className="mb-6">
            <CategoryFilter 
              categories={categories} 
              selectedId={selectedCategory} 
              onSelect={setSelectedCategory} 
            />
          </div>

          {error && (
            <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-6 flex items-center justify-between">
              <span>{error}</span>
              <button 
                onClick={() => setIsSettingsOpen(true)}
                className="text-sm underline hover:text-red-800"
              >
                開啟設定
              </button>
            </div>
          )}

          {initMsg && (
             <div className="flex items-center justify-center p-4 bg-blue-50 text-blue-700 rounded-lg mb-6 border border-blue-100">
               <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-blue-700" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
               </svg>
               {initMsg}
             </div>
          )}

          {isLoading ? (
            <div className="flex items-center justify-center h-64">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
            </div>
          ) : (
            <>
              {selectedCategory === FAVORITES_ID && (
                <div className="mb-4 text-xl font-bold text-gray-800 flex items-center">
                   <span className="mr-2 text-red-500">♥</span> 我的最愛 ({filteredProducts.length})
                </div>
              )}

              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                {filteredProducts.map(product => (
                  <ProductCard 
                    key={product.id} 
                    product={product}
                    isFavorite={favoriteIds.has(product.id)}
                    onToggleFavorite={toggleFavorite}
                    onClick={handleProductClick}
                    onZoom={(img) => setLightboxImage(img)}
                  />
                ))}
              </div>
            </>
          )}

          {!isLoading && filteredProducts.length === 0 && (
             <div className="flex flex-col items-center justify-center h-64 text-gray-500">
               {selectedCategory === FAVORITES_ID ? (
                 <>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                    </svg>
                    <p className="text-lg">尚無最愛商品</p>
                    <p className="text-sm">點擊商品卡片右上角的愛心即可加入</p>
                 </>
               ) : (
                 <>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                    </svg>
                    <p className="text-lg">沒有找到相關商品</p>
                    <p className="text-sm">請嘗試調整搜尋或篩選條件</p>
                 </>
               )}
             </div>
          )}
        </div>
      </div>

      {/* Right Side - Cart */}
      <div className="w-96 bg-white shadow-xl border-l border-gray-200 z-20 flex-shrink-0">
        <Cart 
          items={cart} 
          customer={selectedCustomer}
          orderDiscount={orderDiscount}
          heldOrdersCount={heldOrders.length}
          onSelectCustomer={() => setIsCustomerModalOpen(true)}
          onUpdateQuantity={updateQuantity} 
          onRemove={removeFromCart}
          onUpdateItem={updateItemDetails}
          onClear={clearCart}
          onSetOrderDiscount={setOrderDiscount}
          onCheckout={handleCheckoutRequest} 
          onHoldOrder={handleHoldOrder}
          onOpenHeldOrders={() => setIsHeldOrdersOpen(true)}
        />
      </div>

      {/* Modals & Overlays */}
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={settings}
        onSave={saveSettings}
      />

      <CheckoutModal
        isOpen={isCheckoutOpen}
        onClose={() => setIsCheckoutOpen(false)}
        items={cart}
        customer={selectedCustomer}
        summary={checkoutSummary}
        onConfirm={handleConfirmOrder}
      />

      <OrderHistory
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        orders={orders}
        onUpdateStatus={handleUpdateOrderStatus}
      />

      <CustomerSelectionModal
        isOpen={isCustomerModalOpen}
        onClose={() => setIsCustomerModalOpen(false)}
        customers={customers}
        onSelect={setSelectedCustomer}
      />

      <HeldOrdersModal
        isOpen={isHeldOrdersOpen}
        onClose={() => setIsHeldOrdersOpen(false)}
        heldOrders={heldOrders}
        onRestore={handleRestoreHeldOrder}
        onDelete={handleDeleteHeldOrder}
      />

      <ProductDetailModal
        isOpen={isProductDetailOpen}
        onClose={() => setIsProductDetailOpen(false)}
        product={selectedProduct}
        settings={settings}
        onAddToCart={addToCart}
      />

      <ImageLightbox
        isOpen={!!lightboxImage}
        onClose={() => setLightboxImage(null)}
        imageSrc={lightboxImage}
      />

      <AIAssistant products={products} cart={cart} />

    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Order, OrderStatus } from '../types';

interface OrderHistoryProps {
  isOpen: boolean;
  onClose: () => void;
  orders: Order[];
  onUpdateStatus: (orderId: string, status: OrderStatus) => void;
}

const statusConfig: Record<string, { label: string; color: string; bg: string }> = {
  completed: { label: '已完成', color: 'text-green-700', bg: 'bg-green-100' },
  processing: { label: '處理中', color: 'text-blue-700', bg: 'bg-blue-100' },
  pending: { label: '等待付款', color: 'text-yellow-700', bg: 'bg-yellow-100' },
  'on-hold': { label: '保留', color: 'text-orange-700', bg: 'bg-orange-100' },
  cancelled: { label: '已取消', color: 'text-gray-700', bg: 'bg-gray-100' },
  refunded: { label: '已退款', color: 'text-purple-700', bg: 'bg-purple-100' },
  failed: { label: '失敗', color: 'text-red-700', bg: 'bg-red-100' },
};

const OrderHistory: React.FC<OrderHistoryProps> = ({ isOpen, onClose, orders, onUpdateStatus }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);

  return (
    <>
      {/* Backdrop */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-40 z-40 backdrop-blur-sm transition-opacity"
          onClick={onClose}
        />
      )}

      {/* Slide-over Panel */}
      <div className={`fixed inset-y-0 right-0 max-w-md w-full bg-white shadow-2xl z-50 transform transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="h-full flex flex-col">
          <div className="px-6 py-4 bg-gray-900 text-white flex justify-between items-center shadow-md">
            <h2 className="text-xl font-bold flex items-center">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              歷史訂單
            </h2>
            <button onClick={onClose} className="p-1 hover:bg-gray-700 rounded-full transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 bg-gray-50 custom-scrollbar">
            {orders.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-gray-400 space-y-4">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 opacity-50" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
                </svg>
                <p>暫無訂單紀錄</p>
              </div>
            ) : (
              <div className="space-y-4">
                {orders.slice().reverse().map((order) => {
                  const statusInfo = statusConfig[order.status] || statusConfig.completed;
                  const isTemp = order.id.toString().startsWith('local-');

                  return (
                    <div key={order.id} className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                      <div 
                        className="p-4 flex justify-between items-center cursor-pointer hover:bg-gray-50 transition-colors"
                        onClick={() => setExpandedId(expandedId === order.id ? null : order.id)}
                      >
                        <div>
                          <div className="flex items-center space-x-2">
                             <span className="font-bold text-gray-800">
                               #{isTemp ? 'SYNC...' : order.id.slice(0, 8).toUpperCase()}
                             </span>
                             <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${statusInfo.bg} ${statusInfo.color}`}>
                               {statusInfo.label}
                             </span>
                          </div>
                          <div className="text-xs text-gray-500 mt-1 flex items-center gap-2">
                            {new Date(order.date).toLocaleString()}
                            {isTemp && (
                              <span className="flex items-center text-blue-500 font-medium">
                                <svg className="animate-spin -ml-1 mr-1 h-3 w-3" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                                </svg>
                                傳輸中...
                              </span>
                            )}
                          </div>
                        </div>
                        <div className="text-right">
                          <div className="font-bold text-indigo-600">${Math.round(order.summary.total)}</div>
                          <div className="text-xs text-gray-400">{order.items.length} 件商品</div>
                        </div>
                      </div>

                      {expandedId === order.id && (
                        <div className="bg-gray-50 px-4 py-3 border-t border-gray-100 text-sm space-y-3 animate-fade-in">

                          {/* Status Editor */}
                          <div className="flex items-center justify-between bg-white p-2 rounded-lg border border-gray-200">
                             <label className="text-xs font-bold text-gray-500">更改狀態:</label>
                             <select 
                                value={order.status}
                                onChange={(e) => onUpdateStatus(order.id, e.target.value as OrderStatus)}
                                className="text-sm border-none bg-transparent focus:ring-0 cursor-pointer font-medium text-gray-700"
                                onClick={(e) => e.stopPropagation()}
                                disabled={isTemp}
                             >
                               <option value="pending">等待付款</option>
                               <option value="processing">處理中</option>
                               <option value="on-hold">保留</option>
                               <option value="completed">完成</option>
                               <option value="cancelled">取消</option>
                               <option value="refunded">退款</option>
                               <option value="failed">失敗</option>
                             </select>
                          </div>

                          {/* Customer Info if exists */}
                          {order.customer && (
                             <div className="text-gray-600 text-xs">
                               <p><span className="font-bold">客戶:</span> {order.customer.last_name}{order.customer.first_name}</p>
                               <p><span className="font-bold">電話:</span> {order.customer.phone}</p>
                             </div>
                          )}

                          <div className="space-y-1 pt-1">
                            {order.items.map((item, idx) => (
                              <div key={idx} className="flex justify-between text-gray-700">
                                <span>{item.quantity}x {item.name}</span>
                                <span>${Math.round(parseFloat(item.price) * item.quantity)}</span>
                              </div>
                            ))}
                          </div>

                          <div className="border-t border-gray-200 pt-2 flex justify-between font-bold text-gray-800">
                             <span>總計</span>
                             <span>${Math.round(order.summary.total)}</span>
                          </div>

                          {isTemp && (
                            <div className="text-xs text-blue-500 bg-blue-50 p-2 rounded text-center">
                              正在將訂單同步至 WooCommerce...
                            </div>
                          )}
                          {order.status === 'failed' && (
                            <div className="text-xs text-red-500 bg-red-50 p-2 rounded text-center font-bold">
                              同步失敗。請檢查網路連線或 API 設定。
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      </div>
    </>
  );
};

export default OrderHistory;
